{"cells":[{"cell_type":"code","source":["# Mount Google Drive to access analysis files.\n","\n","from google.colab import drive\n","drive.mount('/content/drive')\n","\n","dir_path = '/content/drive/MyDrive/Personal/Sues/'"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"RH1alzH5XK_D","executionInfo":{"status":"ok","timestamp":1761881367097,"user_tz":-660,"elapsed":30052,"user":{"displayName":"Tomer","userId":"10873557234236150514"}},"outputId":"ce5c29d1-3680-4a92-f18a-7d3ffb70a2d3"},"execution_count":1,"outputs":[{"output_type":"stream","name":"stdout","text":["Mounted at /content/drive\n"]}]},{"cell_type":"code","source":["# Import required libraries.\n","\n","import pandas as pd\n","import requests # Make sure to import requests\n","import time\n","import sys\n","import json\n","from tqdm import tqdm"],"metadata":{"id":"eQtVDglvXUnZ","executionInfo":{"status":"ok","timestamp":1761881370217,"user_tz":-660,"elapsed":487,"user":{"displayName":"Tomer","userId":"10873557234236150514"}}},"execution_count":2,"outputs":[]},{"cell_type":"code","source":["# --- 1. CONFIGURATION ---\n","\n","# --- IMPORTANT ---\n","# This script is now set up to read your API key from Colab's \"Secrets\" feature.\n","# 1. Click the 'Key' icon (Secrets) on the left sidebar in Colab.\n","# 2. Create a new secret named: GEMINI_API_KEY\n","# 3. Paste your API key value into the \"Value\" field.\n","# 4. Make sure \"Notebook access\" is toggled ON.\n","try:\n","    from google.colab import userdata\n","    API_KEY = userdata.get('GEMINI_API_KEY')\n","    if not API_KEY:\n","        print(\"[ERROR] API key 'GEMINI_API_KEY' not found in Colab Secrets.\", file=sys.stderr)\n","        print(\"Please follow the instructions in the script's comments to add it.\", file=sys.stderr)\n","        sys.exit(1) # Exit the script if the key is not found\n","except ImportError:\n","    # This block is a fallback in case you're not running in Colab\n","    print(\"Not running in Colab. Please paste your API key directly into the script.\", file=sys.stderr)\n","    API_KEY = \"\" # <-- PASTE YOUR KEY HERE IF *NOT* USING COLAB SECRETS\n","    if not API_KEY:\n","        print(\"[ERROR] API_KEY is not set. Please paste it into the script.\", file=sys.stderr)\n","        sys.exit(1)\n","except Exception as e:\n","    print(f\"[ERROR] An error occurred while trying to get the API key: {e}\", file=sys.stderr)\n","    sys.exit(1)\n","\n","# ---\n","# Choose which file to analyze\n","INPUT_FILE = dir_path + 'term_analysis_strict_FIXED.csv'\n","OUTPUT_FILE = dir_path + 'ai_validated_strict.csv'\n","\n","# Uncomment the lines below to run the sensitive file instead\n","# INPUT_FILE = 'term_analysis_sensitive_FIXED.csv'\n","# OUTPUT_FILE = 'ai_validated_sensitive.csv'\n","\n","# API Configuration\n","GEMINI_MODEL = 'gemini-2.5-flash-preview-09-2025'\n","API_URL = f\"https://generativelanguage.googleapis.com/v1beta/models/{GEMINI_MODEL}:generateContent?key={API_KEY}\"\n","\n","# --- 2. CORE FUNCTIONS ---\n","\n","def get_ai_validation(context, term, category):\n","    \"\"\"\n","    Calls the Gemini API to validate if a text snippet is relevant.\n","\n","    Args:\n","        context_snippet (str): The sentence(s) where the term was found.\n","        term (str): The specific term that was matched.\n","        category (str): The category of the term (e.g., \"Gender\").\n","\n","    Returns:\n","        str: \"Yes\", \"No\", or \"Error\"\n","    \"\"\"\n","\n","    # Define the system instruction and user prompt\n","    system_prompt = (\n","        \"You are an expert research assistant specializing in biology, sociology, health, and gender studies. \"\n","        \"We are running a study to assess the presence of sex and gender content in Australian universities curricula. \"\n","        \"Your task is to classify a text snippet from a course/unit description based on strict criteria. \"\n","        \"You must determine if the context is *substantively* about sex, gender, or reproduction. \"\n","        \"Respond with ONLY 'Yes' or 'No'.\"\n","    )\n","\n","    user_prompt = (\n","        f\"A search for the term '{term}' (in the category '{category}') found the following context:\\n\\n\"\n","        f\"--- CONTEXT ---\\n{context}\\n--- END CONTEXT ---\\n\\n\"\n","        \"Question: Is this context a *substantive discussion* of sex, gender, or reproduction?\\n\\n\"\n","        \"To be 'Yes', the context must be about the biological, clinical, social, or psychological aspects of these concepts.\\n\"\n","        \"This INCLUDES: \\n\"\n","        \"1. Human concepts (health, sociology, psychology, etc.).\\n\"\n","        \"2. Animal kingdom biology.\\n\"\n","        \"3. Foundational cell biology (e.g., 'cell reproduction', 'meiosis').\\n\\n\"\n","        \"Reply 'No' if the match is irrelevant, such as in the following cases:\\n\"\n","        \"1. PLANT BIOLOGY: The text *only* discusses plants. (Example: 'plant reproduction').\\n\"\n","        \"2. ADMINISTRATIVE/FINANCIAL CONTEXT: The text discusses logistics, payments, or admin. (Example: 'Commonwealth Prac Payment for midwifery').\\n\"\n","        \"3. PURELY SEMANTIC MATCH: The term is part of an unrelated word. (Example: 'man' in 'management').\\n\"\n","        \"4. FIGURATIVE USE: The text uses the term metaphorically. (Example: 'the reproduction of social norms').\\n\\n\"\n","        \"Reply with only 'Yes' or 'No'.\"\n","    )\n","\n","    payload = {\n","        \"contents\": [{\n","            \"parts\": [{\"text\": user_prompt}]\n","        }],\n","        \"systemInstruction\": {\n","            \"parts\": [{\"text\": system_prompt}]\n","        },\n","        \"generationConfig\": {\n","            \"temperature\": 0.0,\n","            \"maxOutputTokens\": 1000 # Using the 1000 token limit\n","        }\n","    }\n","\n","    headers = {'Content-Type': 'application/json'}\n","\n","    try:\n","        # Use exponential backoff for retries\n","        for i in range(5):  # Retry up to 5 times\n","            response = requests.post(API_URL, headers=headers, data=json.dumps(payload), timeout=30)\n","\n","            # Successful call\n","            if response.status_code == 200:\n","                result = response.json()\n","                # [CHANGED] Added more robust JSON parsing\n","                if not result.get('candidates'):\n","                    print(f\"  [!] AI Warning: 'candidates' field missing in response. {result}\", file=sys.stderr)\n","                    return 'No' # Default to 'No' on malformed responses\n","\n","                text = result.get('candidates', [{}])[0].get('content', {}).get('parts', [{}])[0].get('text', 'Error').strip().lower()\n","\n","                if 'yes' in text:\n","                    return 'Yes'\n","                if 'no' in text:\n","                    return 'No'\n","\n","                # If the response is not 'yes' or 'no'\n","                print(f\"  [!] AI Warning: Unexpected response '{text}'. Defaulting to 'No'.\", file=sys.stderr)\n","                return 'No' # Default to 'No' on weird responses\n","\n","            # Rate limiting or server error\n","            elif response.status_code == 429 or response.status_code >= 500:\n","                wait_time = (2 ** i)  # Exponential backoff: 1s, 2s, 4s, 8s, 16s\n","                print(f\"  [!] API Error {response.status_code}. Retrying in {wait_time}s...\", file=sys.stderr)\n","                time.sleep(wait_time)\n","\n","            # Other client-side errors\n","            else:\n","                print(f\"  [!] API Error {response.status_code}: {response.text}\", file=sys.stderr)\n","                return f\"Error: {response.status_code}\"\n","\n","        print(f\"  [!] API Error: Max retries exceeded.\", file=sys.stderr)\n","        return \"Error: Max retries\"\n","\n","    except requests.exceptions.RequestException as e:\n","        print(f\"  [!] Network Error: {e}\", file=sys.stderr)\n","        return f\"Error: Network\"\n","    except Exception as e:\n","        print(f\"  [!] General Error: {e}\", file=sys.stderr)\n","        return f\"Error: General\"\n"],"outputs":[],"execution_count":5,"metadata":{"id":"gnLkYG-pPcym","executionInfo":{"status":"ok","timestamp":1761881513753,"user_tz":-660,"elapsed":718,"user":{"displayName":"Tomer","userId":"10873557234236150514"}}}},{"cell_type":"code","source":["# --- 3. MAIN EXECUTION ---\n","\n","def main():\n","    \"\"\"\n","    Main script execution.\n","    1. Reads the _FIXED.csv file.\n","    2. De-duplicates the work by finding unique (Context, Term) pairs.\n","    3. Calls the AI API for each unique pair.\n","    4. Caches the \"Yes/No\" result.\n","    5. Maps the results back to the full DataFrame.\n","    6. Saves a new \"ai_validated_...\" file.\n","    \"\"\"\n","    print(f\"Starting AI Context Validator for: {INPUT_FILE}\")\n","\n","    try:\n","        df = pd.read_csv(INPUT_FILE)\n","        if 'Context (Sentences)' not in df.columns or 'Term Found' not in df.columns:\n","            print(f\"[ERROR] Input file is missing 'Context (Sentences)' or 'Term Found'.\", file=sys.stderr)\n","            return\n","    except FileNotFoundError:\n","        print(f\"[ERROR] Input file '{INPUT_FILE}' not found.\", file=sys.stderr)\n","        return\n","    except Exception as e:\n","        print(f\"[ERROR] Could not read '{INPUT_FILE}': {e}\", file=sys.stderr)\n","        return\n","\n","    print(f\"Loaded {len(df)} total hits.\")\n","\n","    # 1. De-duplicate the work\n","    # We analyze by unique (Context, Term, Category) triplet\n","    # This ensures we ask \"is 'man' in '...management...' relevant?\" only ONCE.\n","    unique_contexts = df[['Context (Sentences)', 'Term Found', 'Term Category']].drop_duplicates()\n","    print(f\"Found {len(unique_contexts)} unique (Context, Term) pairs to analyze.\")\n","\n","    # 2. Call the AI for each unique pair and cache the result\n","    ai_cache = {} # This will store our \"Yes/No\" results\n","\n","    for index, row in tqdm(unique_contexts.iterrows(), total=unique_contexts.shape[0], desc=\"Validating Contexts\"):\n","        context = str(row['Context (Sentences)'])\n","        term = str(row['Term Found'])\n","        category = str(row['Term Category'])\n","\n","        # Create a unique key for the cache\n","        cache_key = (context, term, category)\n","\n","        # Call the AI\n","        validation_result = get_ai_validation(context, term, category)\n","\n","        ai_cache[cache_key] = validation_result\n","\n","        # IMPORTANT: Be polite to the API.\n","        # Stay just under the 10 RPM limit to avoid 429 errors.\n","        time.sleep(6.1)\n","\n","    print(\"\\nAI analysis complete. Caching finished.\")\n","\n","    # 3. Map the cached results back to the original DataFrame\n","    print(\"Mapping AI validation results back to the full DataFrame...\")\n","\n","    def map_cache_to_row(row):\n","        key = (str(row['Context (Sentences)']), str(row['Term Found']), str(row['Term Category']))\n","        return ai_cache.get(key, \"Error: Not in cache\")\n","\n","    df['ai_is_relevant'] = df.apply(map_cache_to_row, axis=1)\n","\n","    # 4. Save the final, validated file\n","    try:\n","        df.to_csv(OUTPUT_FILE, index=False, encoding='utf-8')\n","        print(f\"\\nSuccessfully saved validated data to '{OUTPUT_FILE}'\")\n","\n","        print(\"\\n--- AI Validation Summary ---\")\n","        print(df['ai_is_relevant'].value_counts().to_string())\n","\n","    except Exception as e:\n","        print(f\"\\n[ERROR] Failed to save final CSV: {e}\", file=sys.stderr)\n","\n","if __name__ == \"__main__\":\n","    main()"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"93v4Yfm9a5mr","executionInfo":{"status":"ok","timestamp":1761883016820,"user_tz":-660,"elapsed":1502043,"user":{"displayName":"Tomer","userId":"10873557234236150514"}},"outputId":"ebdf0ca3-3ea7-467f-f971-ee9c6c89cea5"},"execution_count":6,"outputs":[{"output_type":"stream","name":"stdout","text":["Starting AI Context Validator for: /content/drive/MyDrive/Personal/Sues/term_analysis_strict_FIXED.csv\n","Loaded 252 total hits.\n","Found 178 unique (Context, Term) pairs to analyze.\n"]},{"output_type":"stream","name":"stderr","text":["Validating Contexts: 100%|██████████| 178/178 [25:01<00:00,  8.44s/it]\n"]},{"output_type":"stream","name":"stdout","text":["\n","AI analysis complete. Caching finished.\n","Mapping AI validation results back to the full DataFrame...\n","\n","Successfully saved validated data to '/content/drive/MyDrive/Personal/Sues/ai_validated_strict.csv'\n","\n","--- AI Validation Summary ---\n","ai_is_relevant\n","Yes    178\n","No      74\n"]}]},{"cell_type":"code","source":[],"metadata":{"id":"eJSg38eY-odb"},"execution_count":null,"outputs":[]}],"metadata":{"colab":{"provenance":[]},"kernelspec":{"display_name":"Python 3","name":"python3"}},"nbformat":4,"nbformat_minor":0}